// frontend/src/pages/CadastroEvento.jsx
// ✅ Atualizado para salvar no PostgreSQL via API (Express)
// Tabela eventos (banco):
// id, titulo, data, local, descricao, capacidade_total, vagas_restantes, mapa_url, created_at
// Fotos vão para tabela evento_fotos (opcional) via campo "fotos": ["url1","url2"]

import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const API_URL = "http://localhost:3001"; // ajuste se sua API estiver em outra porta

export default function CadastroEvento({
  onAdd,
  eventoEditando,
  onAtualizar,
  onCancelarEdicao,
}) {
  const navigate = useNavigate();

  // Campos do formulário
  const [titulo, setTitulo] = useState("");
  const [data, setData] = useState("");
  const [local, setLocal] = useState("");
  const [descricao, setDescricao] = useState("");

  const [capacidadeTotal, setCapacidadeTotal] = useState(""); // string no input
  const [mapaUrl, setMapaUrl] = useState("");
  const [fotosTexto, setFotosTexto] = useState("");

  // Preenche formulário no modo editar
  useEffect(() => {
    if (!eventoEditando) return;

    setTitulo(eventoEditando.titulo || "");
    // se vier "2026-12-12T00:00:00.000Z", corta para yyyy-mm-dd
    setData((eventoEditando.data || "").slice(0, 10));
    setLocal(eventoEditando.local || "");
    setDescricao(eventoEditando.descricao || "");

    // ✅ aceita o formato do banco (capacidade_total/mapa_url) e também camelCase antigo
    const cap =
      eventoEditando.capacidade_total ??
      eventoEditando.capacidadeTotal ??
      0;

    setCapacidadeTotal(String(cap));
    setMapaUrl(eventoEditando.mapa_url ?? eventoEditando.mapaUrl ?? "");

    // fotos pode vir como array no JSON do back
    const fotosArr = Array.isArray(eventoEditando.fotos) ? eventoEditando.fotos : [];
    setFotosTexto(fotosArr.join("\n"));
  }, [eventoEditando]);

  function limpar() {
    setTitulo("");
    setData("");
    setLocal("");
    setDescricao("");
    setCapacidadeTotal("");
    setMapaUrl("");
    setFotosTexto("");
  }

  function cancelar() {
    limpar();
    if (eventoEditando && onCancelarEdicao) onCancelarEdicao();
    navigate("/evento");
  }

  function parseFotos(texto) {
    return texto
      .split("\n")
      .map((l) => l.trim())
      .filter(Boolean);
  }

  async function handleSubmit(e) {
    e.preventDefault();

    // ✅ validação básica
    if (!titulo.trim() || !data || !local.trim() || !descricao.trim() || !capacidadeTotal) {
      alert("Preencha todos os campos obrigatórios.");
      return;
    }

    const cap = Number(capacidadeTotal);
    if (Number.isNaN(cap) || cap <= 0) {
      alert("Capacidade total precisa ser maior que 0.");
      return;
    }

    // ✅ payload com NOMES DO BANCO (snake_case)
    const payload = {
      titulo: titulo.trim(),
      data, // yyyy-mm-dd
      local: local.trim(),
      descricao: descricao.trim(),
      capacidade_total: cap,
      mapa_url: mapaUrl.trim() ? mapaUrl.trim() : null,
      fotos: parseFotos(fotosTexto), // opcional (vai para evento_fotos)
    };

    try {
      const isEdit = Boolean(eventoEditando?.id);

      const url = isEdit
        ? `${API_URL}/eventos/${eventoEditando.id}`
        : `${API_URL}/eventos`;

      const method = isEdit ? "PUT" : "POST";

      const resp = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      const dataResp = await resp.json();

      if (!resp.ok) {
        alert(dataResp.erro || dataResp.detalhe || "Erro ao salvar evento.");
        return;
      }

      // ✅ opcional: manter lista do pai sincronizada (se vocês usam isso)
      if (isEdit) {
        if (onAtualizar) onAtualizar(dataResp);
        if (onCancelarEdicao) onCancelarEdicao();
        alert("Evento atualizado com sucesso!");
      } else {
        if (onAdd) onAdd(dataResp);
        alert("Evento cadastrado com sucesso!");
      }

      limpar();
      navigate("/evento");
    } catch (err) {
      alert("Falha ao conectar com a API. Verifique se o backend está rodando.");
    }
  }

  return (
    <section className="stack">
      <h2>{eventoEditando ? "Admin: Editar Evento" : "Admin: Cadastrar Evento"}</h2>

      <form className="form stack" onSubmit={handleSubmit}>
        <label>
          Título
          <input
            className="input"
            value={titulo}
            onChange={(e) => setTitulo(e.target.value)}
          />
        </label>

        <label>
          Data
          <input
            className="input"
            type="date"
            value={data}
            onChange={(e) => setData(e.target.value)}
          />
        </label>

        <label>
          Local
          <input
            className="input"
            value={local}
            onChange={(e) => setLocal(e.target.value)}
          />
        </label>

        <label>
          Descrição
          <input
            className="input"
            value={descricao}
            onChange={(e) => setDescricao(e.target.value)}
          />
        </label>

        <label>
          Capacidade total
          <input
            className="input"
            type="number"
            min={1}
            value={capacidadeTotal}
            onChange={(e) => setCapacidadeTotal(e.target.value)}
            placeholder="Ex: 50"
          />
        </label>

        <label>
          Link do mapa (Google Maps embed)
          <input
            className="input"
            value={mapaUrl}
            onChange={(e) => setMapaUrl(e.target.value)}
            placeholder="Cole um link com output=embed"
          />
        </label>

        <label>
          Fotos (1 URL por linha)
          <textarea
            className="input"
            rows={4}
            value={fotosTexto}
            onChange={(e) => setFotosTexto(e.target.value)}
            placeholder={"https://...\nhttps://...\nhttps://..."}
          />
        </label>

        <div className="row">
          <button className="btn" type="submit">
            {eventoEditando ? "Salvar alterações" : "Salvar"}
          </button>

          <button className="btn ghost" type="button" onClick={limpar}>
            Limpar Formulário
          </button>

          <button className="btn ghost" type="button" onClick={cancelar}>
            Cancelar
          </button>
        </div>
      </form>
    </section>
  );
}
